import{_ as e,o as d,c as i,a3 as o}from"./chunks/framework.DACwFHq9.js";const p=JSON.parse('{"title":"Notely Documentation Audit","description":"","frontmatter":{},"headers":[],"relativePath":"documentation-audit-2026-07-03.md","filePath":"documentation-audit-2026-07-03.md","lastUpdated":1784354374000}'),a={name:"documentation-audit-2026-07-03.md"};function n(l,t,r,s,c,u){return d(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="notely-documentation-audit" tabindex="-1">Notely Documentation Audit <a class="header-anchor" href="#notely-documentation-audit" aria-label="Permalink to &quot;Notely Documentation Audit&quot;">​</a></h1><p>Date: 2026-07-03</p><p>Status note:</p><ul><li>This audit is a point-in-time snapshot of repository and implementation alignment on 2026-07-03.</li><li>Some findings in this report may have been addressed by subsequent documentation and shortcut updates after the audit was written.</li></ul><p>Audited surfaces:</p><ul><li>README.md</li><li>docs/</li><li>in-app Help Center and Keyboard Shortcuts modal</li><li>settings and microcopy surfaces in the renderer</li><li>Electron menu structure and accelerators</li><li>developer-facing docs present in the repository</li></ul><p>Method:</p><ul><li>Code-first verification. No documentation statement was accepted without tracing it to the implementation.</li><li>Sources of truth used for feature existence and naming were Electron menu actions, renderer action handlers, preload APIs, settings UI, and user-facing components.</li></ul><p>Limitations:</p><ul><li>No repository screenshots were present in the audited documentation set, so screenshot accuracy could not be validated.</li><li>This audit covers repository and in-app documentation only. It does not cover any external website, app store listing, or internal release portal.</li></ul><h2 id="executive-summary" tabindex="-1">Executive Summary <a class="header-anchor" href="#executive-summary" aria-label="Permalink to &quot;Executive Summary&quot;">​</a></h2><p>Notely has a broad documentation set, but it is no longer internally consistent with the implementation. The docs cover many major features, yet several labels, shortcuts, settings descriptions, and help surfaces are stale or incomplete. The most serious problem is that keyboard guidance is split across multiple sources and does not match the implemented shortcut map. The second major problem is terminology drift: documentation still refers to &quot;Notes Folder&quot; and &quot;Help -&gt; Documentation&quot; while the application exposes &quot;Open Workspace&quot; and &quot;Help Center&quot;.</p><p>Overall documentation quality: 5.8/10</p><p>Estimated completeness: 72%</p><p>Estimated correctness: 54%</p><p>Highest-priority issues before end-user release:</p><ol><li>Replace the hardcoded keyboard guide with an implementation-backed shortcut source and resolve conflicting bindings.</li><li>Update all user docs from &quot;Notes Folder&quot; and &quot;Help -&gt; Documentation&quot; to the actual UI labels.</li><li>Document currently implemented but undocumented product surfaces: terminal, workspace activity, recent workspaces, favorites/dashboard, reference-note shortcuts, and several settings.</li><li>Add missing release notes/changelog and FAQ surfaces.</li><li>Correct stale AI and storage details in README and developer docs.</li></ol><h2 id="phase-1-verified-feature-inventory" tabindex="-1">Phase 1: Verified Feature Inventory <a class="header-anchor" href="#phase-1-verified-feature-inventory" aria-label="Permalink to &quot;Phase 1: Verified Feature Inventory&quot;">​</a></h2><p>Verified major user-facing surfaces implemented in the codebase:</p><ul><li>Workspace selection and recent workspace reopening</li><li>Note creation, folder creation, rename, remove-to-removed-folder, reload from disk</li><li>Document list in tile and table modes with density controls</li><li>Favorites, recent notes, continue-writing dashboard, task dashboard</li><li>Markdown editing with Edit, Split, Preview, and Web modes</li><li>Markdown validation, typo checking, quick fixes, find, and find/replace</li><li>Outline panel and Focus Mode</li><li>Global search with regex mode and code-block filtering</li><li>Version history compare, restore, delete, and workspace activity history</li><li>Media insertion, asset library, workspace health filters, preview, annotation, and original-image restore</li><li>Screen capture for Windows with Auto Insert and Review Before Insert modes</li><li>Mermaid and Excalidraw support, including image-to-Excalidraw conversion and restore-original flow</li><li>AI settings, AI palette, AI chat, embedding generation, relationship graph, and pattern detection</li><li>Workspace graph with semantic clustering freshness state</li><li>P2P sync status, invites, trusted peers, conflicts, self-test, and key rotation</li><li>Embedded terminal with shell selection</li><li>Command palette with dynamic recent and sibling note commands</li><li>Workspace zip export with raw, PDF, and web modes plus section-mode options</li><li>Help Center, About dialog, and keyboard modal</li><li>Theme, zoom, screen capture, terminal shell, density, view mode, and git metadata controls</li></ul><p>Not implemented as end-user surfaces:</p><ul><li>Plugin or extension system</li><li>Generic import workflow beyond opening an existing workspace and inserting media/reference assets</li><li>Dedicated first-run wizard or tutorial</li><li>Release notes viewer</li><li>FAQ surface</li></ul><h2 id="documentation-coverage-matrix" tabindex="-1">Documentation Coverage Matrix <a class="header-anchor" href="#documentation-coverage-matrix" aria-label="Permalink to &quot;Documentation Coverage Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Implemented</th><th>Documented</th><th>Accurate</th><th>Notes</th></tr></thead><tbody><tr><td>Workspace selection</td><td>Yes</td><td>Yes</td><td>Partial</td><td>Docs say &quot;File -&gt; Notes Folder&quot;; app uses &quot;Open Workspace&quot;.</td></tr><tr><td>Recent workspaces</td><td>Yes</td><td>No</td><td>No</td><td>Implemented in File -&gt; Open Recent and dialog; not documented.</td></tr><tr><td>Create note</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Covered in README and docs.</td></tr><tr><td>Create folder</td><td>Yes</td><td>Yes</td><td>Partial</td><td>Documented loosely; actual command/menu surface not fully described.</td></tr><tr><td>Rename note</td><td>Yes</td><td>Partial</td><td>Partial</td><td>Mentioned in feature reference only; shortcut and menu path omitted.</td></tr><tr><td>Remove note/folder to Removed</td><td>Yes</td><td>No</td><td>No</td><td>Implemented in menu and actions; undocumented workflow.</td></tr><tr><td>Tile/Table view</td><td>Yes</td><td>No</td><td>No</td><td>Implemented via View menu and command palette; absent from docs.</td></tr><tr><td>Density controls</td><td>Yes</td><td>No</td><td>No</td><td>Comfortable/Compact documented nowhere.</td></tr><tr><td>Favorites</td><td>Yes</td><td>No</td><td>No</td><td>Present in dashboard and list actions; undocumented.</td></tr><tr><td>Continue Writing / Recent Notes dashboard</td><td>Yes</td><td>No</td><td>No</td><td>Landing dashboard undocumented.</td></tr><tr><td>Markdown edit/split/preview/web modes</td><td>Yes</td><td>Yes</td><td>Mostly</td><td>Covered, but keyboard mode switching is undocumented.</td></tr><tr><td>Find in note</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Docs reflect current behavior.</td></tr><tr><td>Find and replace</td><td>Yes</td><td>Partial</td><td>Partial</td><td>Exists, but Mac shortcut behavior is undocumented.</td></tr><tr><td>Outline</td><td>Yes</td><td>Yes</td><td>Partial</td><td>Docs omit conflict with reference-link shortcut and Focus mode limitation.</td></tr><tr><td>Focus Mode</td><td>Yes</td><td>Yes</td><td>Partial</td><td>Docs omit shortcut conflict with global search.</td></tr><tr><td>Global search</td><td>Yes</td><td>Yes</td><td>Mostly</td><td>Regex/code-block filtering documented well.</td></tr><tr><td>Version history</td><td>Yes</td><td>Yes</td><td>Mostly</td><td>Core flow documented; storage details drift in README.</td></tr><tr><td>Workspace activity</td><td>Yes</td><td>No</td><td>No</td><td>Implemented via Workspace menu and panel; undocumented.</td></tr><tr><td>Conflict Center</td><td>Yes</td><td>Partial</td><td>Partial</td><td>Sync conflict handling mentioned, dedicated panel/workflow not explained.</td></tr><tr><td>Media library / Workspace Health</td><td>Yes</td><td>Partial</td><td>Partial</td><td>Broadly covered; filters, cleanup behavior, and usage inspector under-documented.</td></tr><tr><td>Screen capture</td><td>Yes</td><td>Yes</td><td>Mostly</td><td>Good coverage, but menu/help terminology is stale.</td></tr><tr><td>Mermaid</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Accurate at high level.</td></tr><tr><td>Excalidraw</td><td>Yes</td><td>Yes</td><td>Mostly</td><td>Core flow documented; some right-click and restore details are fragmented.</td></tr><tr><td>Reference note preview/link insertion</td><td>Yes</td><td>No</td><td>No</td><td>Implemented with shortcuts and toolbar; undocumented.</td></tr><tr><td>Command palette</td><td>Yes</td><td>Partial</td><td>Partial</td><td>Mentioned, but command inventory and personalization are undocumented.</td></tr><tr><td>AI settings</td><td>Yes</td><td>Yes</td><td>Partial</td><td>Docs do not match current provider list and model options.</td></tr><tr><td>AI palette / AI chat</td><td>Yes</td><td>Partial</td><td>Partial</td><td>Broadly described, but actual invocation and shortcut conflicts are inaccurate.</td></tr><tr><td>Workspace graph</td><td>Yes</td><td>Yes</td><td>Mostly</td><td>Core flow documented; refresh and freshness are covered.</td></tr><tr><td>P2P status / invites / peers</td><td>Yes</td><td>Yes</td><td>Partial</td><td>High-level guidance exists; panel tabs and workflows are undocumented.</td></tr><tr><td>Embedded terminal</td><td>Yes</td><td>No</td><td>No</td><td>Fully implemented, entirely undocumented for end users.</td></tr><tr><td>Workspace zip export</td><td>Yes</td><td>Yes</td><td>Partial</td><td>Export formats documented; section export modes are undocumented.</td></tr><tr><td>PDF export</td><td>Yes</td><td>Yes</td><td>Partial</td><td>Exists, but shortcut and some options are not documented.</td></tr><tr><td>Help Center / About</td><td>Yes</td><td>Yes</td><td>Partial</td><td>Docs use stale label &quot;Documentation&quot; instead of &quot;Help Center&quot;.</td></tr><tr><td>Keyboard shortcuts guide</td><td>Yes</td><td>Yes</td><td>No</td><td>In-app modal is materially incomplete and inconsistent.</td></tr><tr><td>Theme</td><td>Yes</td><td>No</td><td>No</td><td>Implemented in Settings menu; undocumented.</td></tr><tr><td>Zoom</td><td>Yes</td><td>No</td><td>No</td><td>Implemented in View menu; undocumented.</td></tr><tr><td>Terminal shell selection</td><td>Yes</td><td>No</td><td>No</td><td>Implemented in View menu and terminal UI; undocumented.</td></tr><tr><td>Screen capture setting</td><td>Yes</td><td>Yes</td><td>Mostly</td><td>Documented accurately.</td></tr><tr><td>Auto-ignore .notes-app in Git</td><td>Yes</td><td>No</td><td>No</td><td>Implemented in document header; undocumented.</td></tr></tbody></table><h2 id="readme-audit" tabindex="-1">README Audit <a class="header-anchor" href="#readme-audit" aria-label="Permalink to &quot;README Audit&quot;">​</a></h2><h3 id="what-is-correct" tabindex="-1">What is correct <a class="header-anchor" href="#what-is-correct" aria-label="Permalink to &quot;What is correct&quot;">​</a></h3><ul><li>Product purpose and overall scope are broadly accurate.</li><li>Build, test, lint, and packaging command names in README match package.json.</li><li>Help Center content is loaded from docs/ and exposed in-app.</li><li>Workspace zip export exists with raw, PDF, and web output modes.</li></ul><h3 id="what-is-inaccurate-or-incomplete" tabindex="-1">What is inaccurate or incomplete <a class="header-anchor" href="#what-is-inaccurate-or-incomplete" aria-label="Permalink to &quot;What is inaccurate or incomplete&quot;">​</a></h3><ol><li><p>README mixes current and stale terminology.</p><ul><li>User docs and README discuss a notes root / notes folder model, but the actual user-facing menu label is Open Workspace.</li><li>In-app help is exposed as Help Center, not Help -&gt; Documentation.</li></ul></li><li><p>Installation guidance is incomplete for end users.</p><ul><li>No supported-OS matrix.</li><li>No end-user install instructions.</li><li>No prerequisites section.</li><li>No environment setup section for AI, signing, or terminal hardening beyond scattered later sections.</li></ul></li><li><p>AI provider and model documentation is stale.</p><ul><li>README lists HuggingFace as an end-user provider concept, but the visible text-provider UI exposes Gemini and Groq while OpenAI and Local LLM are marked unavailable/coming soon.</li><li>README model lists do not match the current AISettings provider arrays.</li></ul></li><li><p>Storage details are partly stale.</p><ul><li>README says <code>.notes-app/settings.json</code> stores workspace-level settings, but the implementation uses <code>.notes-app/app-state.json</code> and <code>.notes-app/app.sqlite</code> for metadata storage.</li></ul></li><li><p>Several implemented features are missing from README.</p><ul><li>Embedded terminal</li><li>Recent workspaces</li><li>Favorites and landing dashboard</li><li>Workspace activity panel</li><li>Reference note preview / insert-reference-link workflows</li><li>Theme, zoom, density, terminal shell, and git metadata controls</li></ul></li><li><p>There are no screenshots.</p></li></ol><h3 id="readme-verdict" tabindex="-1">README verdict <a class="header-anchor" href="#readme-verdict" aria-label="Permalink to &quot;README verdict&quot;">​</a></h3><ul><li>Coverage breadth: good</li><li>Setup/install quality: weak</li><li>Accuracy against current UI labels: weak</li><li>Release-readiness for external users: not sufficient</li></ul><h2 id="docs-folder-audit" tabindex="-1">docs/ Folder Audit <a class="header-anchor" href="#docs-folder-audit" aria-label="Permalink to &quot;docs/ Folder Audit&quot;">​</a></h2><h3 id="strong-areas" tabindex="-1">Strong areas <a class="header-anchor" href="#strong-areas" aria-label="Permalink to &quot;Strong areas&quot;">​</a></h3><ul><li>Global search and regex coverage are relatively strong.</li><li>Workspace export, screen capture, AI setup intent, graph clustering, and task panels are described at a usable high level.</li><li>Troubleshooting contains relevant real workflows rather than placeholder advice.</li></ul><h3 id="systemic-issues" tabindex="-1">Systemic issues <a class="header-anchor" href="#systemic-issues" aria-label="Permalink to &quot;Systemic issues&quot;">​</a></h3><ol><li><p>Terminology drift across nearly every user doc.</p><ul><li>&quot;File -&gt; Notes Folder&quot; should be updated to Open Workspace.</li><li>&quot;Help -&gt; Documentation&quot; should be updated to Help -&gt; Help Center.</li></ul></li><li><p>Documentation claims are spread across too many overlapping pages.</p><ul><li>README, user-guide, feature-reference, top-tasks, and Help Center all repeat the same foundational workflows.</li><li>Keyboard references are split across docs/index.md, the keyboard modal, and actual code.</li></ul></li><li><p>Several major product surfaces are under-documented or absent.</p><ul><li>Terminal</li><li>Recent workspaces</li><li>Favorites/dashboard</li><li>Workspace activity</li><li>Conflict Center</li><li>Theme, zoom, density, terminal shell, git metadata controls</li><li>Reference-note commands</li></ul></li><li><p>Top Tasks is no longer a &quot;Top 15&quot; page.</p><ul><li>It now contains 23 numbered items, including 11b and 19b.</li><li>The title is obsolete.</li></ul></li><li><p>Some docs describe workflows that are only partially true.</p><ul><li>AI docs imply a cleaner provider surface than the actual UI exposes.</li><li>Some storage descriptions blur workspace metadata, note history, and app-state files.</li></ul></li></ol><h3 id="per-document-findings" tabindex="-1">Per-document findings <a class="header-anchor" href="#per-document-findings" aria-label="Permalink to &quot;Per-document findings&quot;">​</a></h3><p>docs/index.md</p><ul><li>Accurate that Help Center reads from docs/.</li><li>Stale label usage: notes folder and Help/Documentation naming.</li><li>Keyboard section is too small and omits most real shortcuts.</li></ul><p>docs/user-guide.md</p><ul><li>Good high-level workflow sequencing.</li><li>Stale workspace terminology.</li><li>Omits recent workspaces, favorites, terminal, workspace activity, theme, zoom, density, and reference-note features.</li></ul><p>docs/feature-reference.md</p><ul><li>Broadest end-user reference and the most valuable single page.</li><li>Contains stale Help and workspace naming.</li><li>Does not cover terminal, recent workspaces, favorites/dashboard, or git metadata controls.</li><li>Under-documents settings and over-compresses platform differences.</li></ul><p>docs/top-tasks.md</p><ul><li>Good procedural format.</li><li>Title is obsolete.</li><li>Uses stale menu labels.</li><li>Omits several daily-use workflows that are more prominent in the UI than some included items.</li></ul><p>docs/feature-availability.md</p><ul><li>Useful conceptually.</li><li>Does not mention terminal or settings surfaces.</li><li>AI setup distinctions are too simplified relative to the current UI.</li></ul><p>docs/data-sync-security.md</p><ul><li>Good for high-level safety framing.</li><li>Too light on actual storage specifics, backup expectations, and what P2P telemetry/conflicts look like.</li></ul><p>docs/troubleshooting.md</p><ul><li>Useful, but missing troubleshooting topics for terminal, workspace export, recent workspaces, graph clustering freshness, and shortcut conflicts.</li></ul><p>docs/ux-writing-guide.md</p><ul><li>Useful internal style guide.</li><li>Not a user-facing doc.</li><li>Should not be treated as part of user help coverage.</li></ul><h2 id="built-in-help-audit" tabindex="-1">Built-in Help Audit <a class="header-anchor" href="#built-in-help-audit" aria-label="Permalink to &quot;Built-in Help Audit&quot;">​</a></h2><p>Implemented help surfaces:</p><ul><li>Help Center modal backed by docs/</li><li>Keyboard Shortcuts modal</li><li>About dialog</li><li>Start Here content in docs/index.md</li><li>Empty states and inline titles/tooltips across components</li></ul><p>Not implemented:</p><ul><li>Welcome screen</li><li>Tutorial</li><li>First-run wizard</li><li>Tips carousel</li><li>Contextual walkthroughs</li></ul><p>Findings:</p><ol><li><p>Help delivery architecture is sound.</p><ul><li>Help metadata is hardcoded in the main process, while markdown body content is loaded from docs/.</li></ul></li><li><p>Help naming is inconsistent.</p><ul><li>UI says Help Center.</li><li>Multiple docs still say Help -&gt; Documentation.</li></ul></li><li><p>Built-in keyboard help is not trustworthy.</p><ul><li>The modal contains only seven shortcuts.</li><li>The implementation contains many more menu and editor bindings.</li></ul></li><li><p>First-run support is weak.</p><ul><li>New users get a splash screen and empty states, but no guided onboarding.</li></ul></li><li><p>Empty states and microcopy quality are generally decent.</p><ul><li>Examples: DocumentList, DashboardPanels, TasksPanel, P2PStatusPanel, WorkspaceActivityPanel, MediaTab.</li><li>The product does provide inline guidance, but those surfaces are not covered in documentation strategy.</li></ul></li></ol><h2 id="menu-documentation-audit" tabindex="-1">Menu Documentation Audit <a class="header-anchor" href="#menu-documentation-audit" aria-label="Permalink to &quot;Menu Documentation Audit&quot;">​</a></h2><p>Documented well enough:</p><ul><li>New Note</li><li>Versions</li><li>Workspace Graph</li><li>P2P Status</li><li>AI Settings</li><li>Screen Capture</li></ul><p>Undocumented or under-documented menu items:</p><ul><li>Open Recent</li><li>Move current folder to Removed</li><li>Workspace Activity</li><li>Show Terminal</li><li>Terminal Shell: Auto / Bash / CMD</li><li>Theme: System / Light / Dark</li><li>Density controls</li><li>Zoom In / Out / Reset</li><li>Run Sync Self-Test</li><li>Conflict Center</li><li>Rotate Workspace Keys</li><li>How Sync Works</li><li>Generate Embeddings / Build Relationship Graph / Detect Patterns / Clear Cache</li><li>Open in VS Code</li><li>Open Website View</li><li>Reload from Disk</li></ul><h2 id="settings-documentation-audit" tabindex="-1">Settings Documentation Audit <a class="header-anchor" href="#settings-documentation-audit" aria-label="Permalink to &quot;Settings Documentation Audit&quot;">​</a></h2><p>Documented:</p><ul><li>AI settings, at a high level</li><li>Screen Capture mode</li></ul><p>Missing or incomplete:</p><ul><li>Theme preference</li><li>Zoom factor</li><li>Tile vs Table view mode</li><li>Comfortable vs Compact density</li><li>Terminal visibility and shell preference</li><li>Typo Check toggle</li><li>Auto-ignore <code>.notes-app</code> in <code>.gitignore</code></li><li>Workspace export section modes</li><li>AI advanced generation controls: max tokens and temperature</li><li>AI feature toggles: pattern learning, embeddings, relationship discovery</li></ul><p>Documentation quality of settings descriptions: insufficient. The code exposes the controls, but the docs do not explain defaults, impact, or recommended usage for most of them.</p><h2 id="workflow-documentation-audit" tabindex="-1">Workflow Documentation Audit <a class="header-anchor" href="#workflow-documentation-audit" aria-label="Permalink to &quot;Workflow Documentation Audit&quot;">​</a></h2><p>Well-covered workflows:</p><ul><li>Create note</li><li>Edit markdown</li><li>Find / replace</li><li>Global search</li><li>Version recovery</li><li>Screen capture</li><li>Mermaid / Excalidraw basics</li><li>Workspace zip export</li><li>Task review</li></ul><p>Partially covered workflows:</p><ul><li>P2P sync pairing and conflict resolution</li><li>AI setup and use</li><li>Media cleanup and annotations</li><li>PDF export</li></ul><p>Missing workflows:</p><ul><li>Recent workspace reopening</li><li>Workspace activity review</li><li>Favorites and dashboard usage</li><li>Terminal usage and shell switching</li><li>Reference note preview and insert-reference-link flows</li><li>Theme / density / zoom customization</li><li>Remove-to-removed-folder and recovery expectations</li><li>Git metadata handling for <code>.notes-app</code></li></ul><h2 id="missing-documentation-by-severity" tabindex="-1">Missing Documentation by Severity <a class="header-anchor" href="#missing-documentation-by-severity" aria-label="Permalink to &quot;Missing Documentation by Severity&quot;">​</a></h2><h3 id="critical" tabindex="-1">Critical <a class="header-anchor" href="#critical" aria-label="Permalink to &quot;Critical&quot;">​</a></h3><ul><li>Full keyboard shortcut inventory is missing and the current in-app guide is inaccurate.</li><li>Actual shortcut conflicts are undocumented and unresolved.</li><li>Core menu/help terminology is stale across user docs.</li></ul><h3 id="high" tabindex="-1">High <a class="header-anchor" href="#high" aria-label="Permalink to &quot;High&quot;">​</a></h3><ul><li>No changelog or release notes.</li><li>No FAQ.</li><li>Terminal feature undocumented.</li><li>Settings coverage incomplete for theme, zoom, density, terminal shell, AI advanced settings, and git metadata controls.</li><li>Recent workspaces and workspace activity undocumented.</li></ul><h3 id="medium" tabindex="-1">Medium <a class="header-anchor" href="#medium" aria-label="Permalink to &quot;Medium&quot;">​</a></h3><ul><li>Dashboard, favorites, and continue-writing surfaces undocumented.</li><li>Conflict Center and sync self-test workflows undocumented.</li><li>Workspace export section-mode options undocumented.</li><li>Reference note preview/link insertion workflows undocumented.</li><li>First-run onboarding is minimal and undocumented.</li></ul><h3 id="low" tabindex="-1">Low <a class="header-anchor" href="#low" aria-label="Permalink to &quot;Low&quot;">​</a></h3><ul><li>Empty states and tooltip strategy are undocumented.</li><li>Top Tasks title is stale.</li><li>Some developer docs duplicate or overstate AI capabilities.</li></ul><h2 id="keyboard-shortcut-audit" tabindex="-1">Keyboard Shortcut Audit <a class="header-anchor" href="#keyboard-shortcut-audit" aria-label="Permalink to &quot;Keyboard Shortcut Audit&quot;">​</a></h2><h3 id="key-findings" tabindex="-1">Key findings <a class="header-anchor" href="#key-findings" aria-label="Permalink to &quot;Key findings&quot;">​</a></h3><ol><li><p>The keyboard guide is incomplete.</p><ul><li>The in-app modal shows 7 shortcuts.</li><li>The implementation exposes many more.</li></ul></li><li><p>Three real conflicts exist in the current implementation.</p><ul><li>Ctrl/Cmd+K is used for both Command Palette and Open AI Palette.</li><li>Ctrl/Cmd+Shift+F is used for both Global Search and Focus Mode.</li><li>Ctrl/Cmd+Shift+L is used for both Show Outline and Insert Reference Link.</li></ul></li><li><p>Platform behavior is not documented.</p><ul><li>Find and Replace has a Ctrl/Cmd+H accelerator only on non-macOS in the app menu.</li></ul></li></ol><h3 id="shortcut-table" tabindex="-1">Shortcut table <a class="header-anchor" href="#shortcut-table" aria-label="Permalink to &quot;Shortcut table&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Shortcut</th><th>Action</th><th>Where it works</th><th>Scope / conditions</th><th>Documented?</th><th>Notes</th></tr></thead><tbody><tr><td>Ctrl/Cmd+K</td><td>Open Command Palette</td><td>Global renderer</td><td>Window-level keydown</td><td>Partial</td><td>Documented, but conflicts with AI Palette menu accelerator.</td></tr><tr><td>Ctrl/Cmd+K</td><td>Open AI Palette</td><td>Document screen menu</td><td>Electron menu accelerator</td><td>No</td><td>Conflicts with Command Palette.</td></tr><tr><td>Ctrl/Cmd+Shift+F</td><td>Open Global Search</td><td>Global renderer</td><td>Window-level keydown</td><td>Partial</td><td>Documented in keyboard modal, but conflicts with Focus Mode.</td></tr><tr><td>Ctrl/Cmd+Shift+F</td><td>Toggle Focus Mode</td><td>Document editor</td><td>Window-level keydown and View menu</td><td>Partial</td><td>Documented as menu workflow, not as conflicting shortcut.</td></tr><tr><td>Ctrl/Cmd+/</td><td>Open Keyboard Shortcuts</td><td>Global</td><td>Window-level keydown and Help menu</td><td>Yes</td><td>One of the few consistent shortcuts.</td></tr><tr><td>F1</td><td>Open Help Center</td><td>Global</td><td>Help menu accelerator</td><td>Partial</td><td>Docs still say Help -&gt; Documentation.</td></tr><tr><td>Ctrl/Cmd+N</td><td>New Note</td><td>Landing and document</td><td>File menu and command palette</td><td>Yes</td><td>Accurate.</td></tr><tr><td>Ctrl/Cmd+Shift+N</td><td>Open Workspace</td><td>Landing and document</td><td>File menu and command palette</td><td>No</td><td>Docs still describe File -&gt; Notes Folder.</td></tr><tr><td>Ctrl/Cmd+S</td><td>Save current note</td><td>Document</td><td>File menu and editor keydown</td><td>Partial</td><td>Exists, but not consistently documented in user docs.</td></tr><tr><td>Ctrl/Cmd+Shift+E</td><td>Export PDF</td><td>Document</td><td>File menu</td><td>No</td><td>User docs mention note PDF export, not the shortcut.</td></tr><tr><td>Ctrl/Cmd+Shift+E</td><td>Export Workspace as Zip</td><td>Landing</td><td>File menu</td><td>No</td><td>Export workflow documented, shortcut not.</td></tr><tr><td>Ctrl/Cmd+Shift+H</td><td>Versions</td><td>Document</td><td>File menu</td><td>Yes</td><td>Accurate.</td></tr><tr><td>Ctrl/Cmd+Shift+O</td><td>Open in VS Code</td><td>Document</td><td>File menu</td><td>No</td><td>Undocumented.</td></tr><tr><td>Ctrl/Cmd+Shift+W</td><td>Open Website View</td><td>Landing and document</td><td>File menu</td><td>No</td><td>Undocumented.</td></tr><tr><td>F2</td><td>Rename Note</td><td>Document</td><td>File menu</td><td>No</td><td>Undocumented.</td></tr><tr><td>Ctrl/Cmd+Shift+R</td><td>Reload from Disk</td><td>Document</td><td>File menu</td><td>No</td><td>Undocumented.</td></tr><tr><td>Ctrl/Cmd+Delete</td><td>Move Note to Removed</td><td>Document</td><td>File menu</td><td>No</td><td>Undocumented.</td></tr><tr><td>Ctrl/Cmd+Shift+Delete</td><td>Move Folder to Removed</td><td>Landing</td><td>File menu</td><td>No</td><td>Undocumented.</td></tr><tr><td>Esc</td><td>Back to Notes</td><td>Document</td><td>File menu</td><td>Partial</td><td>Behavior exists, but docs do not describe it.</td></tr><tr><td>Ctrl/Cmd+F</td><td>Find in Current Note</td><td>Document</td><td>Edit menu, CodeMirror keymap, editor hook</td><td>Yes</td><td>Accurate.</td></tr><tr><td>Ctrl/Cmd+H</td><td>Find and Replace</td><td>Document</td><td>Edit menu, non-macOS accelerator</td><td>Partial</td><td>Keyboard modal incorrectly implies universal availability.</td></tr><tr><td>Ctrl/Cmd+Shift+L</td><td>Show Outline</td><td>Document</td><td>View menu accelerator</td><td>Partial</td><td>Conflicts with Insert Reference Link.</td></tr><tr><td>Ctrl/Cmd+Shift+L</td><td>Insert Reference Link</td><td>Document</td><td>Toolbar document keydown</td><td>No</td><td>Undocumented and conflicts with Show Outline.</td></tr><tr><td>Ctrl/Cmd+Shift+K</td><td>Open Reference Note</td><td>Document</td><td>Toolbar document keydown</td><td>No</td><td>Undocumented.</td></tr><tr><td>Ctrl/Cmd+Shift+S</td><td>Capture Screen Area</td><td>Document</td><td>Toolbar document keydown</td><td>Yes</td><td>Documented procedurally, not in keyboard guide.</td></tr><tr><td>Ctrl/Cmd+Z</td><td>Undo</td><td>Document</td><td>CodeMirror keymap and editor hook</td><td>No</td><td>Visible in tooltips, undocumented in guide.</td></tr><tr><td>Ctrl/Cmd+Y</td><td>Redo</td><td>Document</td><td>CodeMirror keymap and editor hook</td><td>No</td><td>Visible in tooltips, undocumented in guide.</td></tr><tr><td>Ctrl/Cmd+Shift+Z</td><td>Redo</td><td>Document</td><td>CodeMirror keymap</td><td>No</td><td>Undocumented.</td></tr><tr><td>Ctrl/Cmd+\\</td><td>Split Preview</td><td>Document</td><td>View menu and editor hook</td><td>No</td><td>Undocumented shortcut.</td></tr><tr><td>Ctrl/Cmd+1</td><td>Tile Notes</td><td>Landing</td><td>View menu</td><td>No</td><td>Context-specific landing shortcut.</td></tr><tr><td>Ctrl/Cmd+2</td><td>Table Notes</td><td>Landing</td><td>View menu</td><td>No</td><td>Context-specific landing shortcut.</td></tr><tr><td>Ctrl/Cmd+3</td><td>Comfortable Density</td><td>Landing</td><td>View menu</td><td>No</td><td>Context-specific landing shortcut.</td></tr><tr><td>Ctrl/Cmd+4</td><td>Compact Density</td><td>Landing</td><td>View menu</td><td>No</td><td>Context-specific landing shortcut.</td></tr><tr><td>Ctrl/Cmd+1</td><td>Edit Mode</td><td>Document</td><td>Editor hook</td><td>No</td><td>Context-specific document shortcut.</td></tr><tr><td>Ctrl/Cmd+2</td><td>Split Mode</td><td>Document</td><td>Editor hook</td><td>No</td><td>Context-specific document shortcut.</td></tr><tr><td>Ctrl/Cmd+3</td><td>Preview Mode</td><td>Document</td><td>Editor hook</td><td>No</td><td>Context-specific document shortcut.</td></tr><tr><td>Ctrl/Cmd+=</td><td>Zoom In</td><td>Landing and document</td><td>View menu</td><td>No</td><td>Undocumented.</td></tr><tr><td>Ctrl/Cmd+-</td><td>Zoom Out</td><td>Landing and document</td><td>View menu</td><td>No</td><td>Undocumented.</td></tr><tr><td>Ctrl/Cmd+0</td><td>Reset Zoom</td><td>Landing and document</td><td>View menu</td><td>No</td><td>Undocumented.</td></tr><tr><td>Ctrl/Cmd+Shift+P</td><td>Open P2P Status</td><td>Global</td><td>P2P menu</td><td>No</td><td>Undocumented shortcut.</td></tr><tr><td>Ctrl/Cmd+Shift+,</td><td>Open AI Settings</td><td>Global</td><td>AI menu</td><td>No</td><td>Undocumented shortcut.</td></tr><tr><td>Ctrl/Cmd+Shift+G</td><td>Open Workspace Graph</td><td>Global</td><td>Workspace menu</td><td>No</td><td>Workflow documented, shortcut not.</td></tr><tr><td>Ctrl/Cmd+Shift+A</td><td>Open Workspace Activity</td><td>Landing and document</td><td>File or Workspace menu</td><td>No</td><td>Undocumented.</td></tr><tr><td>Enter</td><td>Next find match</td><td>Find panel</td><td>Find UI only</td><td>No</td><td>Tooltip only.</td></tr><tr><td>Shift+Enter</td><td>Previous find match</td><td>Find panel</td><td>Find UI only</td><td>No</td><td>Tooltip only.</td></tr><tr><td>ContextMenu or Shift+F10</td><td>Open preview context menu</td><td>Markdown preview</td><td>Preview surface only</td><td>No</td><td>Accessibility-oriented shortcut, undocumented.</td></tr><tr><td>Plus</td><td>Zoom image in</td><td>Media preview</td><td>Image preview only</td><td>No</td><td>Undocumented.</td></tr><tr><td>Minus</td><td>Zoom image out</td><td>Media preview</td><td>Image preview only</td><td>No</td><td>Undocumented.</td></tr><tr><td>1 or 0</td><td>Reset image zoom</td><td>Media preview</td><td>Image preview only</td><td>No</td><td>Undocumented.</td></tr></tbody></table><h2 id="inconsistencies" tabindex="-1">Inconsistencies <a class="header-anchor" href="#inconsistencies" aria-label="Permalink to &quot;Inconsistencies&quot;">​</a></h2><ol><li><p>Code vs docs: workspace naming</p><ul><li>Docs repeatedly say File -&gt; Notes Folder.</li><li>UI/menu uses Open Workspace.</li></ul></li><li><p>Code vs docs: help naming</p><ul><li>Docs say Help -&gt; Documentation.</li><li>UI/menu uses Help Center.</li></ul></li><li><p>Code vs in-app keyboard guide</p><ul><li>KeyboardShortcutsModal shows only seven shortcuts.</li><li>Menu and editor implement many more.</li></ul></li><li><p>Code vs code: shortcut ownership conflicts</p><ul><li>Ctrl/Cmd+K</li><li>Ctrl/Cmd+Shift+F</li><li>Ctrl/Cmd+Shift+L</li></ul></li><li><p>Code vs README/docs: AI providers and models</p><ul><li>README and AI README overstate available provider surface.</li><li>AISettings marks OpenAI and Local as unavailable / coming soon.</li></ul></li><li><p>Code vs README: storage details</p><ul><li>README references <code>.notes-app/settings.json</code>.</li><li>Metadata storage uses <code>.notes-app/app-state.json</code> and <code>.notes-app/app.sqlite</code>.</li></ul></li><li><p>Code vs docs: menu surface coverage</p><ul><li>Recent workspaces, terminal, workspace activity, theme, zoom, density, git metadata status, and reference-note flows exist but are not documented.</li></ul></li></ol><h2 id="obsolete-documentation" tabindex="-1">Obsolete Documentation <a class="header-anchor" href="#obsolete-documentation" aria-label="Permalink to &quot;Obsolete Documentation&quot;">​</a></h2><ul><li>docs/top-tasks.md title: no longer &quot;Top 15&quot;</li><li>docs/index.md: stale notes-folder and Help/Documentation terminology</li><li>docs/user-guide.md: stale notes-folder and Help/Documentation terminology</li><li>docs/feature-reference.md: stale Help/Documentation terminology and stale notes-folder terminology</li><li>docs/top-tasks.md: stale Help/Documentation terminology and stale notes-folder terminology</li><li>docs/troubleshooting.md: stale notes-folder terminology</li><li>README.md: storage details partially stale; AI/provider details partially stale; setup/install guidance incomplete</li><li>src/ai/README.md: overstates available providers and uses Cmd+K AI palette guidance that conflicts with current app behavior</li></ul><h2 id="documentation-quality-review" tabindex="-1">Documentation Quality Review <a class="header-anchor" href="#documentation-quality-review" aria-label="Permalink to &quot;Documentation Quality Review&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Score (1-10)</th><th>Notes</th></tr></thead><tbody><tr><td>Completeness</td><td>7</td><td>Broad feature coverage exists, but several implemented surfaces are missing.</td></tr><tr><td>Correctness</td><td>5</td><td>Too many stale labels and shortcut mismatches.</td></tr><tr><td>Consistency</td><td>4</td><td>Terminology and shortcut references are fragmented.</td></tr><tr><td>Readability</td><td>8</td><td>Most docs are easy to read.</td></tr><tr><td>Navigation</td><td>7</td><td>Help Center structure is usable.</td></tr><tr><td>Discoverability</td><td>5</td><td>Important features exist without docs or guided discovery.</td></tr><tr><td>Onboarding quality</td><td>4</td><td>Splash + Start Here is not enough for first-time users.</td></tr><tr><td>Troubleshooting quality</td><td>6</td><td>Useful but incomplete.</td></tr><tr><td>Searchability</td><td>7</td><td>docs/ pages are topic-based and searchable.</td></tr></tbody></table><h2 id="end-user-perspective" tabindex="-1">End-User Perspective <a class="header-anchor" href="#end-user-perspective" aria-label="Permalink to &quot;End-User Perspective&quot;">​</a></h2><p>Can a new user install it?</p><ul><li>Not confidently from current docs. There is no end-user installation guide or platform support section.</li></ul><p>Can they understand the UI?</p><ul><li>Partially. The docs explain the major note-editing model, but the actual menu and settings labels do not line up with the guide.</li></ul><p>Can they discover features?</p><ul><li>Only partially. The command palette, terminal, workspace activity, recent workspaces, favorites, and several settings are easy to miss.</li></ul><p>Can they recover from mistakes?</p><ul><li>Better than average for notes and media. Version history, removed-folder flow, and image restore exist. Documentation of all recovery paths does not.</li></ul><p>Can they learn shortcuts?</p><ul><li>No. The keyboard guide is materially incomplete and current shortcuts conflict.</li></ul><p>Can they understand settings?</p><ul><li>Only AI and screen capture at a high level. Most other settings are undocumented.</li></ul><p>Can they troubleshoot issues?</p><ul><li>Some common cases yes, but not terminal, recent workspace, export, graph freshness, or shortcut conflicts.</li></ul><p>Can they use advanced functionality?</p><ul><li>Only after experimentation. P2P, AI tuning, terminal, graph refresh, and workspace export options need stronger docs.</li></ul><h2 id="suggested-improvements" tabindex="-1">Suggested Improvements <a class="header-anchor" href="#suggested-improvements" aria-label="Permalink to &quot;Suggested Improvements&quot;">​</a></h2><h3 id="_1-critical-fixes" tabindex="-1">1. Critical fixes <a class="header-anchor" href="#_1-critical-fixes" aria-label="Permalink to &quot;1. Critical fixes&quot;">​</a></h3><ul><li>Resolve the three shortcut conflicts in implementation.</li><li>Generate the keyboard guide from the actual command/accelerator map.</li><li>Replace all stale menu labels in README and docs.</li></ul><h3 id="_2-high-value-additions" tabindex="-1">2. High-value additions <a class="header-anchor" href="#_2-high-value-additions" aria-label="Permalink to &quot;2. High-value additions&quot;">​</a></h3><ul><li>Add release notes / changelog.</li><li>Add FAQ.</li><li>Add end-user installation and supported-platform guide.</li><li>Add settings reference page.</li></ul><h3 id="_3-ux-improvements" tabindex="-1">3. UX improvements <a class="header-anchor" href="#_3-ux-improvements" aria-label="Permalink to &quot;3. UX improvements&quot;">​</a></h3><ul><li>Add a first-run onboarding sheet or setup checklist in-app.</li><li>Add contextual help for terminal, recent workspaces, workspace activity, and reference-note workflows.</li></ul><h3 id="_4-documentation-restructuring" tabindex="-1">4. Documentation restructuring <a class="header-anchor" href="#_4-documentation-restructuring" aria-label="Permalink to &quot;4. Documentation restructuring&quot;">​</a></h3><ul><li>Reduce duplication across README, user-guide, feature-reference, and top-tasks.</li><li>Keep README external-facing and concise.</li><li>Keep docs/ as the canonical in-app help set.</li></ul><h3 id="_5-navigation-improvements" tabindex="-1">5. Navigation improvements <a class="header-anchor" href="#_5-navigation-improvements" aria-label="Permalink to &quot;5. Navigation improvements&quot;">​</a></h3><ul><li>Add a dedicated shortcut reference page in docs/.</li><li>Add a settings reference page in docs/.</li><li>Add an advanced workflows page for P2P, AI, terminal, and export.</li></ul><h3 id="_6-onboarding-enhancements" tabindex="-1">6. Onboarding enhancements <a class="header-anchor" href="#_6-onboarding-enhancements" aria-label="Permalink to &quot;6. Onboarding enhancements&quot;">​</a></h3><ul><li>Replace &quot;Start Here&quot; with a real first-run path that includes opening a workspace, creating a note, editing, searching, and recovery.</li></ul><h3 id="_7-help-system-improvements" tabindex="-1">7. Help system improvements <a class="header-anchor" href="#_7-help-system-improvements" aria-label="Permalink to &quot;7. Help system improvements&quot;">​</a></h3><ul><li>Rename all doc references to Help Center.</li><li>Surface missing workflows directly from related panels.</li></ul><h3 id="_8-keyboard-guide-improvements" tabindex="-1">8. Keyboard guide improvements <a class="header-anchor" href="#_8-keyboard-guide-improvements" aria-label="Permalink to &quot;8. Keyboard guide improvements&quot;">​</a></h3><ul><li>Show scope, platform notes, and conflicts.</li><li>Split global, editor, media preview, and context-menu shortcuts.</li><li>Include only real bindings, not aspirational ones.</li></ul><h2 id="final-scorecard" tabindex="-1">Final Scorecard <a class="header-anchor" href="#final-scorecard" aria-label="Permalink to &quot;Final Scorecard&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Surface</th><th>Score (1-10)</th></tr></thead><tbody><tr><td>README</td><td>6</td></tr><tr><td>User Guide</td><td>6</td></tr><tr><td>Help System</td><td>6</td></tr><tr><td>Keyboard Guide</td><td>2</td></tr><tr><td>Setup Instructions</td><td>4</td></tr><tr><td>Troubleshooting</td><td>6</td></tr><tr><td>API / Developer Docs</td><td>5</td></tr><tr><td>Consistency</td><td>4</td></tr><tr><td>Completeness</td><td>7</td></tr><tr><td>Overall Documentation Quality</td><td>5.8</td></tr></tbody></table><h2 id="release-readiness-roadmap" tabindex="-1">Release-Readiness Roadmap <a class="header-anchor" href="#release-readiness-roadmap" aria-label="Permalink to &quot;Release-Readiness Roadmap&quot;">​</a></h2><p>Before releasing Notely broadly to end users, complete this sequence:</p><ol><li>Fix shortcut conflicts in code and replace the hardcoded keyboard modal with generated data.</li><li>Normalize all docs to current UI terminology: Open Workspace, Help Center, Help -&gt; Keyboard Shortcuts.</li><li>Publish a real install/setup guide and a changelog.</li><li>Add missing documentation for terminal, workspace activity, recent workspaces, dashboard/favorites, settings, and reference-note workflows.</li><li>Update AI and storage documentation to match the current implementation exactly.</li><li>Add lightweight first-run onboarding and link it from the landing empty state and Help Center.</li></ol><p>If those six items are completed, documentation quality would move from internal-tooling grade to a credible end-user release baseline.</p>',138)])])}const h=e(a,[["render",n]]);export{p as __pageData,h as default};
